"use client";

import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
);

interface AQICardProps {
  city: string;
  data?: any;
  loading: boolean;
}

export default function AQICard({ city, data, loading }: AQICardProps) {
  if (loading) return <div>Loading {city}...</div>;
  if (!data) return <div>Data not available for {city}</div>;

  const getAQIColor = (aqi: number) => {
    if (aqi <= 50) return "#22c55e";
    if (aqi <= 100) return "#eab308";
    if (aqi <= 150) return "#f97316";
    if (aqi <= 200) return "#dc2626";
    if (aqi <= 300) return "#7c3aed";
    return "#475569";
  };

  const labels =
    data.forecast?.daily.pm25.map((d: { day?: string }, i: number) => {
      const date = d.day
        ? new Date(d.day)
        : new Date(Date.now() + i * 24 * 60 * 60 * 1000);
      return date.toLocaleDateString("en-US", { weekday: "short" });
    }) || [];

  const chartData = {
    labels,
    datasets: [
      {
        label: "PM2.5",
        data:
          data.forecast?.daily.pm25.map((d: { avg: number }) => d.avg) || [],
        backgroundColor: data.forecast?.daily.pm25.map((d: { avg: number }) =>
          getAQIColor(d.avg),
        ),
        borderRadius: 6,
        borderSkipped: false,
      },
    ],
  };

  const chartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { display: false },
      title: { display: true, text: "5-Day PM2.5 AQI Forecast" },
      tooltip: {
        callbacks: {
          label: (context: any) => `AQI: ${context.raw}`,
        },
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        ticks: { stepSize: 50 },
      },
    },
  };

  return (
    <div
      className="glass-card p-5 rounded-2xl shadow-lg w-full box-border transition-all"
      style={{
        color: "var(--foreground)",
      }}
    >
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-2 mb-4">
        <h2
          className="text-2xl font-bold text-left"
          style={{ color: "var(--foreground)" }}
        >
          {city}
        </h2>
        <div className="flex gap-2 flex-wrap">
          <span
            className="px-2 py-0.5 rounded-full font-medium text-xs shadow-sm"
            style={{
              backgroundColor: getAQIColor(data.aqi),
              color: "var(--foreground)",
            }}
          >
            AQI: {data.aqi}
          </span>
          <span
            className="px-2 py-0.5 rounded-full font-medium text-xs shadow-sm"
            style={{
              backgroundColor: "var(--gray-200)",
              color: "var(--foreground)",
            }}
          >
            Dominant: {data.dominentpol}
          </span>
        </div>
      </div>

      {/* Chart */}
      <div className="h-48">
        <Bar data={chartData} options={chartOptions} />
      </div>
    </div>
  );
}
