"use client";

import { cityMapping } from "./lib/cityMapping";
import AQICard from "./components/AQICard";
import { useAQIData } from "./hooks/useAQIData";
import { useTheme } from "./context/themeContext"; // <-- import hook

export default function Home() {
  const { data, loading, error } = useAQIData();
  const cities = Object.keys(cityMapping);

  const { theme, toggleTheme } = useTheme(); // <-- access theme

  return (
    <div className="relative w-screen min-h-screen overflow-x-hidden flex items-center justify-center">
      {/* Background video */}
      <video
        className="absolute top-0 left-0 w-full h-full object-cover"
        autoPlay
        loop
        muted
        playsInline
        src="/globe.mp4"
      />

      {/* Semi-transparent overlay */}
      <div className="absolute top-0 left-0 w-full h-full bg-black/70"></div>

      {/* Dashboard content */}
      <main className="relative z-10 w-full max-w-[1200px] px-4 text-center">
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-3xl md:text-4xl font-bold text-white">
            Kosovo Air Quality
          </h1>

          {/* Theme toggle button */}
          <button
            onClick={toggleTheme}
            className="px-4 py-2 rounded-full bg-gray-200 dark:bg-gray-800 text-gray-800 dark:text-gray-200 transition-colors"
          >
            {theme === "light" ? "Dark Mode" : "Light Mode"}
          </button>
        </div>

        {error && <p className="text-red-600 mb-4">Error fetching data</p>}

        {/* Grid layout: 2 columns mobile, 3+ larger screens */}
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-3 gap-3 w-full">
          {cities.map((cityKey) => (
            <AQICard
              key={cityKey}
              city={cityMapping[cityKey]}
              data={data[cityKey]}
              loading={loading}
            />
          ))}
        </div>
      </main>
    </div>
  );
}
